#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int coins[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &coins[i]);
        }
        qsort(coins, N, sizeof(int), compare);
        int time = 0;
        for (int i = 0; i < N; i++) {
            int target = i + 1;
            while (coins[i] > target) {
                int move = K;
                if (coins[i] - target < K) {
                    move = coins[i] - target;
                }
                coins[i] -= move;
                time++;
            }
        }
        printf("%d\n", time);
    }
    return 0;
}

